// Generates the 33 <AtlasFigure> MDX wrapper pages + 6 theme gallery pages
// under atlas-docs/, per H486 §4.1 / §6 step 4. Re-run after adding/renaming
// a visualization or changing the theme grouping below — it always overwrites
// its own generated files (marked with the header comment) and never touches
// hand-authored atlas-docs/intro.md.
//
// H490: every page carries a REAL per-visualization trust block (`source`) —
// the actual source artifact, n, and data date — replacing the H486 generic
// placeholder. Counts audited against data/*.csv on 10-07-2026.
import { writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = dirname(dirname(fileURLToPath(import.meta.url)));
const outDir = join(root, 'atlas-docs');

const GENERATED_HEADER = '{/* Generated by scripts/generate-atlas-mdx.mjs — do not hand-edit, re-run the script instead. */}\n\n';

const D = 'данные на 10-07-2026';
const KHR = 'датировки — факты по Хрусталёву (2026)';

