let position = 1;

for (const theme of THEMES) {
  const themeDir = join(outDir, theme.slug);
  mkdirSync(themeDir, { recursive: true });

  writeFileSync(
    join(themeDir, '_category_.json'),
    JSON.stringify({ label: theme.title, position: position++, link: { type: 'generated-index' } }, null, 2) + '\n',
  );

  for (const page of theme.pages) {
    const yamlTitle = JSON.stringify(page.title);
    const toolNote = page.tool
      ? '\n:::note[Инструмент]\nЭто утилита для записи видео, а не исследовательская визуализация — оставлена в галерее как рабочий инструмент атласа.\n:::\n'
      : '';
    const mdx = `---
title: ${yamlTitle}
---

${GENERATED_HEADER}# ${page.title}
${toolNote}
<AtlasFigure src="${page.file}" title={${yamlTitle}} caption={${yamlTitle}} source={${JSON.stringify(page.source)}} />
`;
    writeFileSync(join(themeDir, `${page.slug}.mdx`), mdx);
  }
}

console.log(
  `[generate-atlas-mdx] wrote ${THEMES.reduce((n, t) => n + t.pages.length, 0)} figure pages across ${THEMES.length} themes`,
);
